      '../../packages/docs/src/' + pathRemainder
    );
  }
  ,
  async (path) => {
    if (!/^(?:\.\.[\\/]\.\.[\\/]packages[\\/]docs[\\/]src[\\/]components[\\/](?!\.)(?=.)[^\\/]*?\.mdx)$/.exec(path)) {
      return;
    }

    const pathRemainder = path.substring(35);
