      /* webpackInclude: /(?!.*node_modules)(?:[\\/]packages[\\/]docs[\\/]src[\\/]components[\\/](?!\.)(?=.)[^\\/]*?\.mdx)$/ */
      '../../packages/docs/src/components/' + pathRemainder
