  async (path) => {
    if (!/^(?:\.\.[\\/]\.\.[\\/]packages[\\/]docs[\\/]src[\\/]tokens[\\/](?!\.)(?=.)[^\\/]*?\.mdx)$/.exec(path)) {
      return;
    }

    const pathRemainder = path.substring(31);
