      /* webpackInclude: /(?!.*node_modules)(?:[\\/]packages[\\/]docs[\\/]src[\\/]tokens[\\/](?!\.)(?=.)[^\\/]*?\.mdx)$/ */
      '../../packages/docs/src/tokens/' + pathRemainder
    );
  }
  ,
  async (path) => {
    if (!/^(?:\.\.[\\/]\.\.[\\/]packages[\\/]docs[\\/]src[\\/]functional[\\/](?!\.)(?=.)[^\\/]*?\.mdx)$/.exec(path)) {
      return;
    }

    const pathRemainder = path.substring(35);
    return import(
      /* webpackChunkName: "[request]" */
      /* webpackInclude: /(?!.*node_modules)(?:[\\/]packages[\\/]docs[\\/]src[\\/]functional[\\/](?!\.)(?=.)[^\\/]*?\.mdx)$/ */
      '../../packages/docs/src/functional/' + pathRemainder
