  }
  ,
  async (path) => {
    if (!/^(?:\.\.[\\/]\.\.[\\/]packages[\\/]docs[\\/]src[\\/]angular[\\/](?!\.)(?=.)[^\\/]*?\.mdx)$/.exec(path)) {
      return;
    }

    const pathRemainder = path.substring(32);
