      /* webpackInclude: /(?!.*node_modules)(?:[\\/]packages[\\/]docs[\\/]src[\\/]angular[\\/](?!\.)(?=.)[^\\/]*?\.mdx)$/ */
      '../../packages/docs/src/angular/' + pathRemainder
    );
  }
  ,
  async (path) => {
    if (!/^(?:\.\.[\\/]\.\.[\\/]packages[\\/]angular[\\/]src(?:[\\/](?!\.)(?:(?:(?!(?:^|[\\/])\.).)*?)[\\/]|[\\/]|$)(?!\.)(?=.)[^\\/]*?\.stories\.(ts|mdx))$/.exec(path)) {
      return;
    }

    const pathRemainder = path.substring(27);
    return import(
      /* webpackChunkName: "[request]" */
      /* webpackInclude: /(?!.*node_modules)(?:[\\/]packages[\\/]angular[\\/]src(?:[\\/](?!\.)(?:(?:(?!(?:^|[\\/])\.).)*?)[\\/]|[\\/]|$)(?!\.)(?=.)[^\\/]*?\.stories\.(ts|mdx))$/ */
      '../../packages/angular/src/' + pathRemainder
    );
  }

];

export async function importFn(path) {
  for (let i = 0; i < importers.length; i++) {
    const moduleExports = await pipeline(() => importers[i](path));
    if (moduleExports) {
      return moduleExports;
    }
  }
}
